<?php

function fail(string $message): never {
    fwrite(STDERR, "ERROR: {$message}\n");
    exit(1);
}

function writeFileUtf8(string $path, string $content): void {
    if (file_put_contents($path, $content) === false) {
        fail("No se pudo guardar {$path}");
    }
}

$root = dirname(__DIR__);

/*
|--------------------------------------------------------------------------
| Rutas
|--------------------------------------------------------------------------
*/
$routesPath = $root.'/routes/comercio.php';
$routes = file_get_contents($routesPath);

if ($routes === false) {
    fail('No se pudo leer routes/comercio.php');
}

if (! str_contains($routes, 'CommerceCatalogController')) {
    $routes = str_replace(
        "use App\\Http\\Controllers\\Comercio\\CommerceBrandingController;",
        "use App\\Http\\Controllers\\Comercio\\CommerceBrandingController;\nuse App\\Http\\Controllers\\Comercio\\CommerceCatalogController;",
        $routes
    );
}

if (! str_contains($routes, "catalog.products.store")) {
    $anchor = "            Route::post(\n                '/branding',";

    $block = <<<'PHP'

            /*
            |--------------------------------------------------------------------------
            | Catálogos
            |--------------------------------------------------------------------------
            */

            Route::post(
                '/catalogos/categorias',
                [CommerceCatalogController::class, 'storeCategory']
            )->name('catalog.categories.store');

            Route::post(
                '/catalogos/marcas',
                [CommerceCatalogController::class, 'storeBrand']
            )->name('catalog.brands.store');

            Route::post(
                '/catalogos/productos',
                [CommerceCatalogController::class, 'storeProduct']
            )->name('catalog.products.store');

            Route::put(
                '/catalogos/productos/{product}',
                [CommerceCatalogController::class, 'updateProduct']
            )->name('catalog.products.update');

            Route::patch(
                '/catalogos/productos/{product}/visibilidad',
                [CommerceCatalogController::class, 'toggleVisibility']
            )->name('catalog.products.visibility');

            Route::delete(
                '/catalogos/productos/{product}',
                [CommerceCatalogController::class, 'destroyProduct']
            )->name('catalog.products.destroy');

PHP;

    $position = strpos($routes, $anchor);

    if ($position === false) {
        fail('No se encontro el punto para insertar rutas de catalogos');
    }

    $routes = substr($routes, 0, $position).$block.substr($routes, $position);
}

writeFileUtf8($routesPath, $routes);

/*
|--------------------------------------------------------------------------
| CommerceUser
|--------------------------------------------------------------------------
*/
$userPath = $root.'/app/Models/Comercio/CommerceUser.php';
$user = file_get_contents($userPath);

if ($user === false) {
    fail('No se pudo leer CommerceUser.php');
}

if (! str_contains($user, 'catalogProducts(): HasMany')) {
    $method = <<<'PHP'

    public function catalogCategories(): HasMany
    {
        return $this->hasMany(
            CommerceCatalogCategory::class,
            'commerce_user_id'
        );
    }

    public function catalogBrands(): HasMany
    {
        return $this->hasMany(
            CommerceCatalogBrand::class,
            'commerce_user_id'
        );
    }

    public function catalogProducts(): HasMany
    {
        return $this->hasMany(
            CommerceCatalogProduct::class,
            'commerce_user_id'
        );
    }
PHP;

    $lastBrace = strrpos($user, '}');

    if ($lastBrace === false) {
        fail('No se encontro el cierre de CommerceUser');
    }

    $user = substr($user, 0, $lastBrace).$method."\n}\n";
}

writeFileUtf8($userPath, $user);

/*
|--------------------------------------------------------------------------
| DashboardController
|--------------------------------------------------------------------------
*/
$controllerPath = $root.'/app/Http/Controllers/Comercio/DashboardController.php';
$controller = file_get_contents($controllerPath);

if ($controller === false) {
    fail('No se pudo leer DashboardController.php');
}

foreach ([
    'CommerceCatalogCategory',
    'CommerceCatalogBrand',
    'CommerceCatalogProduct',
] as $model) {
    $use = "use App\\Models\\Comercio\\{$model};";

    if (! str_contains($controller, $use)) {
        $controller = str_replace(
            "use App\\Models\\Comercio\\CommerceBranding;",
            "use App\\Models\\Comercio\\CommerceBranding;\n{$use}",
            $controller
        );
    }
}

if (! str_contains($controller, '$catalogCategories =')) {
    $anchor = <<<'PHP'
        $branding = CommerceBranding::query()
            ->where('commerce_user_id', $comercio->id)
            ->first();
PHP;

    $queries = $anchor.<<<'PHP'


        $catalogCategories = CommerceCatalogCategory::query()
            ->where('commerce_user_id', $comercio->id)
            ->orderBy('sort_order')
            ->orderBy('name')
            ->get();

        $catalogBrands = CommerceCatalogBrand::query()
            ->where('commerce_user_id', $comercio->id)
            ->orderBy('name')
            ->get();

        $catalogProducts = CommerceCatalogProduct::query()
            ->with([
                'category',
                'brand',
                'variants',
                'stocks.branch',
            ])
            ->where('commerce_user_id', $comercio->id)
            ->latest('id')
            ->get();
PHP;

    if (! str_contains($controller, $anchor)) {
        fail('No se encontro la consulta de branding en DashboardController');
    }

    $controller = str_replace($anchor, $queries, $controller);
}

$controller = str_replace(
    "            'branding',\n",
    "            'branding',\n            'catalogos',\n",
    $controller
);

if (! str_contains($controller, "'catalogCategories' =>")) {
    $controller = str_replace(
        "            'branding' => \$branding,\n",
        "            'branding' => \$branding,\n            'catalogCategories' => \$catalogCategories,\n            'catalogBrands' => \$catalogBrands,\n            'catalogProducts' => \$catalogProducts,\n",
        $controller
    );
}

writeFileUtf8($controllerPath, $controller);

/*
|--------------------------------------------------------------------------
| Dashboard Blade
|--------------------------------------------------------------------------
*/
$dashboardPath = $root.'/resources/views/comercio/dashboard.blade.php';
$dashboard = file_get_contents($dashboardPath);

if ($dashboard === false) {
    fail('No se pudo leer dashboard.blade.php');
}

$oldButton = <<<'BLADE'
            <button type="button" class="commerce-admin__tab" disabled>
                Catálogos
            </button>
BLADE;

$newButton = <<<'BLADE'
            <button
                type="button"
                class="commerce-admin__tab {{ ($activeTab ?? 'usuarios') === 'catalogos' ? 'is-active' : '' }}"
                data-commerce-tab-button="catalogos"
                aria-pressed="{{ ($activeTab ?? 'usuarios') === 'catalogos' ? 'true' : 'false' }}"
            >
                Catálogos
            </button>
BLADE;

if (str_contains($dashboard, $oldButton)) {
    $dashboard = str_replace($oldButton, $newButton, $dashboard);
}

if (! str_contains($dashboard, 'data-commerce-tab-panel="catalogos"')) {
    $brandingMarker = 'data-commerce-tab-panel="branding"';
    $markerPosition = strpos($dashboard, $brandingMarker);

    if ($markerPosition === false) {
        fail('No se encontro el panel Branding para insertar Catalogos');
    }

    $panelStart = strrpos(substr($dashboard, 0, $markerPosition), '<div');

    if ($panelStart === false) {
        fail('No se encontro el inicio del panel Branding');
    }

    $panel = base64_decode('', true);

    if ($panel === false) {
        fail('No se pudo decodificar el panel Catalogos');
    }

    $dashboard = substr($dashboard, 0, $panelStart)
        .$panel."\n"
        .substr($dashboard, $panelStart);
}

if (! str_contains($dashboard, 'comercio-catalogos.css')) {
    $styleAnchor = <<<'BLADE'
    <link
        rel="stylesheet"
        href="{{ asset('assets/petpay-card/css/portals/comercio-branding.css') }}?v=20260711-04"
    >
BLADE;

    $styleInsert = $styleAnchor.<<<'BLADE'

    <link
        rel="stylesheet"
        href="{{ asset('assets/petpay-card/css/portals/comercio-catalogos.css') }}?v=20260712-01"
    >
BLADE;

    $dashboard = str_replace($styleAnchor, $styleInsert, $dashboard);
}

if (! str_contains($dashboard, 'comercio-catalogos.js')) {
    $scriptAnchor = <<<'BLADE'
    <script src="{{ asset('assets/petpay-card/js/portals/comercio-branding.js') }}?v=20260711-04"></script>
BLADE;

    $scriptInsert = $scriptAnchor.<<<'BLADE'

    <script src="{{ asset('assets/petpay-card/js/portals/comercio-catalogos.js') }}?v=20260712-01"></script>
BLADE;

    $dashboard = str_replace($scriptAnchor, $scriptInsert, $dashboard);
}

writeFileUtf8($dashboardPath, $dashboard);

echo "OK: Modulo Catalogos instalado.\n";